eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   attractions: () => (/* binding */ attractions),\n/* harmony export */   blogPosts: () => (/* binding */ blogPosts),\n/* harmony export */   cultureSections: () => (/* binding */ cultureSections),\n/* harmony export */   destinations: () => (/* binding */ destinations),\n/* harmony export */   galleryImages: () => (/* binding */ galleryImages),\n/* harmony export */   stats: () => (/* binding */ stats),\n/* harmony export */   testimonials: () => (/* binding */ testimonials)\n/* harmony export */ });\n// ─── Destinations ────────────────────────────────────────────────────────────\nconst destinations = [\n    {\n        id: 1,\n        slug: 'lake-tana',\n        name: 'Lake Tana',\n        tagline: 'The Source of the Blue Nile',\n        description: 'Lake Tana is Ethiopia\\'s largest lake, stretching over 3,600 km² at an altitude of 1,788 m above sea level. The lake is the source of the Blue Nile River and is home to 37 islands adorned with ancient monasteries dating back to the 14th century. Its tranquil papyrus-lined shores, diverse birdlife, and stunning sunsets make it one of Africa\\'s most enchanting bodies of water.',\n        image: '/images/lake-tana.jpg',\n        gallery: [\n            '/images/gal-02.jpg',\n            '/images/gal-11.jpg',\n            '/images/gal-03.jpg'\n        ],\n        facts: [\n            'Covers an area of 3,600 km² — Ethiopia\\'s largest lake',\n            'Home to 37 islands, 20 of which have ancient monasteries',\n            'Source of the Blue Nile, which joins the White Nile at Khartoum',\n            'Over 200 species of birds have been recorded around the lake',\n            'Listed as a UNESCO Biosphere Reserve since 2015'\n        ],\n        activities: [\n            'Boat tours to island monasteries',\n            'Bird watching',\n            'Fishing with local papyrus boats',\n            'Sunset cruises',\n            'Visiting Zege Peninsula'\n        ],\n        bestSeason: 'October – February',\n        category: 'Nature',\n        rating: 4.9,\n        reviews: 1842,\n        duration: '1–3 days',\n        difficulty: 'Easy'\n    },\n    {\n        id: 2,\n        slug: 'blue-nile-falls',\n        name: 'Blue Nile Falls',\n        tagline: 'The Smoke of Fire — Tis Abay',\n        description: 'Known locally as Tis Abay (Smoke of Fire), the Blue Nile Falls is one of Ethiopia\\'s most spectacular natural wonders. Located 30 km south of Bahir Dar, the falls plunge about 45 metres over a basalt ledge creating a perpetual mist and rainbow-filled spectacle. During the rainy season, the falls stretch nearly 400 metres wide, earning comparisons to Niagara Falls.',\n        image: '/images/blue-nile-falls.jpg',\n        gallery: [\n            '/images/gal-01.jpg',\n            '/images/gal-05.jpg',\n            '/images/gal-09.jpg'\n        ],\n        facts: [\n            'Falls drop approximately 45 metres into a dramatic gorge',\n            'Up to 400 metres wide during peak rainy season (July–September)',\n            'Local name \"Tis Abay\" translates to \"Smoke of Fire\" in Amharic',\n            'A Portuguese bridge from the 17th century crosses the Nile nearby',\n            'A 40-minute hike through lush farmland leads to the viewpoint'\n        ],\n        activities: [\n            'Hiking to the falls',\n            'Photography',\n            'Crossing the Blue Nile gorge',\n            'Village walks',\n            'Swimming in natural pools (dry season)'\n        ],\n        bestSeason: 'October – December (post-rains, full flow)',\n        category: 'Nature',\n        rating: 4.8,\n        reviews: 2156,\n        duration: 'Half day',\n        difficulty: 'Easy to Moderate'\n    },\n    {\n        id: 3,\n        slug: 'bahir-dar-city',\n        name: 'Bahir Dar City',\n        tagline: 'Ethiopia\\'s Garden City',\n        description: 'Bahir Dar is the capital of the Amhara region and one of Ethiopia\\'s most modern and planned cities. Wide, palm-lined boulevards, colorful markets, boutique cafés, and a lively waterfront promenade make it a perfect base for exploring the region. The city blends urban sophistication with traditional Ethiopian hospitality, offering world-class cuisine, artisan crafts, and vibrant nightlife.',\n        image: '/images/bahir-dar-city.jpg',\n        gallery: [\n            '/images/gal-03.jpg',\n            '/images/gal-07.jpg',\n            '/images/gal-13.jpg'\n        ],\n        facts: [\n            'Population of approximately 350,000 — one of Ethiopia\\'s fastest growing cities',\n            'Sits at 1,801 m above sea level with a pleasant year-round climate',\n            'Named \"The Garden City\" for its tree-lined boulevards',\n            'Major hub for universities and research institutions',\n            'Famous for its traditional woven textiles and silver jewellery'\n        ],\n        activities: [\n            'Exploring the lakeshore promenade',\n            'Visiting local markets',\n            'Cultural museum tours',\n            'Tasting traditional cuisine',\n            'Shopping for handicrafts'\n        ],\n        bestSeason: 'Year-round',\n        category: 'City',\n        rating: 4.7,\n        reviews: 987,\n        duration: '2–4 days',\n        difficulty: 'Easy'\n    },\n    {\n        id: 4,\n        slug: 'bezawit-hill',\n        name: 'Bezawit Hill',\n        tagline: 'Panoramic Views Above the Lake',\n        description: 'Bezawit Hill rises steeply above Bahir Dar, offering some of the most breathtaking panoramic views of Lake Tana and the surrounding landscape. The hill is home to the former palace of Emperor Haile Selassie and a striking equestrian statue. At sunrise and sunset, the view of the lake shimmering in golden light is simply unforgettable, making it one of the top photography spots in the region.',\n        image: '/images/bezawit-hill.jpg',\n        gallery: [\n            '/images/gal-06.jpg',\n            '/images/gal-10.jpg',\n            '/images/gal-14.jpg'\n        ],\n        facts: [\n            'Offers 360° panoramic views of Lake Tana and Bahir Dar city',\n            'Former retreat palace of Emperor Haile Selassie I',\n            'Features a prominent equestrian statue of the Emperor',\n            'Reached via a steep paved road — suitable for vehicles and hikers',\n            'Best visited at sunrise or sunset for spectacular photography'\n        ],\n        activities: [\n            'Sunrise/sunset photography',\n            'Hiking',\n            'Palace viewing',\n            'Panoramic sightseeing',\n            'Picnicking'\n        ],\n        bestSeason: 'Year-round',\n        category: 'Scenic',\n        rating: 4.6,\n        reviews: 743,\n        duration: '2–3 hours',\n        difficulty: 'Easy to Moderate'\n    },\n    {\n        id: 5,\n        slug: 'monasteries',\n        name: 'Lake Tana Monasteries',\n        tagline: 'Sacred Islands of Ancient Christianity',\n        description: 'The islands of Lake Tana are home to some of Ethiopia\\'s oldest and most revered Orthodox Christian monasteries. Founded between the 13th and 17th centuries, these island sanctuaries preserve extraordinary collections of illuminated manuscripts, royal crowns, ceremonial crosses, and ancient paintings. The monasteries of Ura Kidane Mehret, Kibran Gabriel, and Narga Selassie are particularly celebrated for their artistic and historical significance.',\n        image: '/images/monasteries.jpg',\n        gallery: [\n            '/images/gal-04.jpg',\n            '/images/gal-08.jpg',\n            '/images/gal-12.jpg'\n        ],\n        facts: [\n            'Over 20 island monasteries, some dating back to the 14th century',\n            'Houses the mummified remains of several Ethiopian emperors',\n            'Ancient illuminated Gospels and royal treasures preserved on site',\n            'Some monasteries restrict entry to male visitors only',\n            'The islands served as safe havens for the Ark of the Covenant during foreign invasions'\n        ],\n        activities: [\n            'Boat trips to island monasteries',\n            'Viewing ancient manuscripts',\n            'Learning Ethiopian Orthodox history',\n            'Photography of murals',\n            'Meeting resident monks'\n        ],\n        bestSeason: 'October – April',\n        category: 'Heritage',\n        rating: 4.9,\n        reviews: 1631,\n        duration: 'Full day',\n        difficulty: 'Easy'\n    }\n];\n// ─── Attractions ─────────────────────────────────────────────────────────────\nconst attractions = [\n    {\n        id: 1,\n        name: 'Blue Nile Falls',\n        category: 'Nature',\n        rating: 4.9,\n        image: '/images/att-blue-nile.jpg',\n        description: 'Ethiopia\\'s most spectacular waterfall, known locally as Tis Abay — Smoke of Fire.',\n        price: 'ETB 300',\n        duration: 'Half day',\n        location: '30 km south of Bahir Dar'\n    },\n    {\n        id: 2,\n        name: 'Ura Kidane Mehret',\n        category: 'Heritage',\n        rating: 4.9,\n        image: '/images/att-ura-kidane.jpg',\n        description: 'The most visited monastery on Lake Tana, famed for its extraordinary 17th-century murals.',\n        price: 'ETB 200',\n        duration: '2–3 hours',\n        location: 'Zege Peninsula, Lake Tana'\n    },\n    {\n        id: 3,\n        name: 'Lake Tana Islands',\n        category: 'Nature',\n        rating: 4.8,\n        image: '/images/att-lake-tana.jpg',\n        description: 'Explore the 37 mystical islands of Lake Tana, many sheltering ancient monasteries.',\n        price: 'ETB 500 (boat)',\n        duration: 'Full day',\n        location: 'Lake Tana'\n    },\n    {\n        id: 4,\n        name: 'Kibran Gabriel',\n        category: 'Heritage',\n        rating: 4.7,\n        image: '/images/att-kibran.jpg',\n        description: 'A male-only monastery island housing royal mummies and precious ecclesiastical treasures.',\n        price: 'ETB 200',\n        duration: '2–3 hours',\n        location: 'Lake Tana island'\n    },\n    {\n        id: 5,\n        name: 'Narga Selassie',\n        category: 'Heritage',\n        rating: 4.8,\n        image: '/images/att-narga.jpg',\n        description: 'An 18th-century island monastery built by Empress Mentewab — a masterpiece of Ethiopian architecture.',\n        price: 'ETB 200',\n        duration: '2–3 hours',\n        location: 'Dek Island, Lake Tana'\n    },\n    {\n        id: 6,\n        name: 'Bahir Dar Market',\n        category: 'Culture',\n        rating: 4.5,\n        image: '/images/att-market.jpg',\n        description: 'Vibrant local market offering handwoven textiles, silver jewellery, spices, and traditional crafts.',\n        price: 'Free',\n        duration: '1–2 hours',\n        location: 'Central Bahir Dar'\n    },\n    {\n        id: 7,\n        name: 'Bezawit Hill',\n        category: 'Scenic',\n        rating: 4.6,\n        image: '/images/att-bezawit.jpg',\n        description: 'Hilltop retreat of Emperor Haile Selassie with sweeping panoramas of Lake Tana.',\n        price: 'ETB 100',\n        duration: '2–3 hours',\n        location: 'Northern Bahir Dar'\n    },\n    {\n        id: 8,\n        name: 'Debre Maryam',\n        category: 'Heritage',\n        rating: 4.6,\n        image: '/images/att-debre.jpg',\n        description: 'A serene island monastery with beautifully painted traditional Ethiopian Christian art.',\n        price: 'ETB 150',\n        duration: '2 hours',\n        location: 'Lake Tana island'\n    },\n    {\n        id: 9,\n        name: 'Zege Peninsula',\n        category: 'Nature',\n        rating: 4.7,\n        image: '/images/att-zege.jpg',\n        description: 'A lush peninsula extending into Lake Tana, covered in ancient coffee forest and monasteries.',\n        price: 'ETB 100',\n        duration: 'Half day',\n        location: 'Lake Tana shoreline'\n    }\n];\n// ─── Culture ─────────────────────────────────────────────────────────────────\nconst cultureSections = [\n    {\n        id: 1,\n        title: 'Traditional Food',\n        icon: 'utensils',\n        color: 'from-orange-500 to-amber-400',\n        items: [\n            {\n                name: 'Injera',\n                description: 'A spongy sourdough flatbread made from teff grain — the cornerstone of every Ethiopian meal, used as both plate and utensil.'\n            },\n            {\n                name: 'Doro Wot',\n                description: 'Ethiopia\\'s beloved national dish — slow-simmered chicken stew in rich berbere spice blend, traditionally served on holidays.'\n            },\n            {\n                name: 'Tibs',\n                description: 'Pan-fried meat (beef or lamb) sautéed with onions, tomatoes, and green peppers, a favourite in Bahir Dar restaurants.'\n            },\n            {\n                name: 'Shiro',\n                description: 'A hearty stew made from ground chickpea or bean flour with spices — a staple protein source, especially during fasting periods.'\n            },\n            {\n                name: 'Kitfo',\n                description: 'Minced beef seasoned with spiced butter (niter kibbeh) and mitmita chilli, served raw or lightly cooked.'\n            },\n            {\n                name: 'Fish from Lake Tana',\n                description: 'Freshwater tilapia and catfish grilled or fried, a local specialty unique to Bahir Dar\\'s waterfront restaurants.'\n            }\n        ]\n    },\n    {\n        id: 2,\n        title: 'Festivals & Celebrations',\n        icon: 'star',\n        color: 'from-purple-600 to-pink-500',\n        items: [\n            {\n                name: 'Timkat (Epiphany)',\n                description: 'Ethiopia\\'s most colourful religious festival celebrating Christ\\'s baptism. Held in January, with vibrant processions to lakes and rivers.'\n            },\n            {\n                name: 'Enkutatash (New Year)',\n                description: 'Ethiopian New Year falls in September, celebrated with bonfires, singing children carrying bouquets of flowers, and festive gatherings.'\n            },\n            {\n                name: 'Meskel (Finding of the True Cross)',\n                description: 'A September festival featuring massive bonfire ceremonies (demera) and joyful communal celebrations.'\n            },\n            {\n                name: 'Genna (Christmas)',\n                description: 'Ethiopian Christmas on January 7th, celebrated with early morning church services and traditional food and games.'\n            },\n            {\n                name: 'Fasika (Easter)',\n                description: 'The holiest festival in the Ethiopian Orthodox calendar, preceded by 55 days of fasting and marked with all-night vigils and feasting.'\n            }\n        ]\n    },\n    {\n        id: 3,\n        title: 'Traditional Clothing',\n        icon: 'shirt',\n        color: 'from-teal-500 to-green-400',\n        items: [\n            {\n                name: 'Habesha Kemis',\n                description: 'The iconic traditional white dress for women, made of hand-woven cotton with intricate coloured embroidery on the borders.'\n            },\n            {\n                name: 'Netela',\n                description: 'A lightweight white shawl worn by both men and women, draped elegantly over the shoulders, especially for religious occasions.'\n            },\n            {\n                name: 'Gabi',\n                description: 'A thicker, double-layered white cotton wrap worn by men, perfect for cool highland mornings and evenings.'\n            },\n            {\n                name: 'Tilf',\n                description: 'Decorative coloured woven borders (typically red, green, or yellow) on white garments, reflecting regional identity.'\n            }\n        ]\n    },\n    {\n        id: 4,\n        title: 'Music & Dance',\n        icon: 'music',\n        color: 'from-blue-500 to-indigo-400',\n        items: [\n            {\n                name: 'Eskista',\n                description: 'Ethiopia\\'s traditional dance form characterised by bold, rhythmic shoulder and chest movements — expressive, energetic, and unique.'\n            },\n            {\n                name: 'Begena',\n                description: 'A large ancient lyre known as \"The Harp of David\", traditionally played during fasting periods and spiritual meditations.'\n            },\n            {\n                name: 'Masenqo',\n                description: 'A one-stringed bowed lute played by professional wandering minstrels (azmaris) who improvise poetic songs.'\n            },\n            {\n                name: 'Krar',\n                description: 'A six-stringed lyre at the heart of Ethiopian folk and pop music, with a bright, resonant tone.'\n            }\n        ]\n    }\n];\n// ─── Blog Posts ───────────────────────────────────────────────────────────────\nconst blogPosts = [\n    {\n        id: 1,\n        slug: 'history-of-bahir-dar',\n        title: 'The Rich History of Bahir Dar: From Ancient Shores to Modern City',\n        excerpt: 'Explore the fascinating history of Bahir Dar, from its origins as a small fishing village on Lake Tana to becoming one of Ethiopia\\'s most vibrant modern cities.',\n        content: `Bahir Dar, the capital of the Amhara Regional State, sits on the southern shore of Lake Tana at an altitude of about 1,801 metres above sea level. Its name literally means \"sea side\" in Amharic — a fitting descriptor for a city defined by water.\n\nThe area around present-day Bahir Dar has been inhabited for millennia. Archaeological evidence suggests settlements around Lake Tana dating back thousands of years, drawn by the lake's abundant fish, fertile shores, and strategic position. The lake's island monasteries, some founded as early as the 13th century, testify to the region's deep spiritual and cultural significance.\n\n**The Imperial Era**\n\nDuring the Imperial period, Bahir Dar's importance grew significantly. Emperor Haile Selassie I took particular interest in the city, commissioning modern infrastructure and educational institutions. The construction of the wide, palm-lined boulevards that give Bahir Dar its distinctive \"garden city\" appearance dates largely from this era. Bezawit Hill, where a retreat palace was built for the Emperor, remains a landmark today.\n\n**Post-Revolution Development**\n\nFollowing the 1974 revolution that ended Imperial rule, Bahir Dar continued to develop as a regional centre. The establishment of Bahir Dar University (now one of Ethiopia's largest, with over 30,000 students) transformed the city into a centre of education and research. Textile factories and other industries brought economic development and population growth.\n\n**Today's Bahir Dar**\n\nToday, Bahir Dar is one of Ethiopia's fastest-growing cities with a population of approximately 350,000. It combines modern amenities with traditional charm — waterfront hotels and restaurants sit alongside age-old boat builders crafting papyrus tankwa vessels by hand. The city's well-planned layout, UNESCO-recognized lake environs, and proximity to world-class natural attractions make it one of Africa's most compelling travel destinations.`,\n        category: 'History',\n        author: 'Almaz Bekele',\n        authorAvatar: '/images/gal-12.jpg',\n        date: '2024-02-15',\n        readTime: '8 min read',\n        image: '/images/blog-history.jpg',\n        tags: [\n            'History',\n            'Bahir Dar',\n            'Ethiopia',\n            'Culture'\n        ],\n        likes: 234\n    },\n    {\n        id: 2,\n        slug: 'exploring-lake-tana',\n        title: 'Exploring Lake Tana: Islands, Monasteries and Papyrus Boats',\n        excerpt: 'A complete guide to navigating Lake Tana\\'s sacred islands, from the famous Ura Kidane Mehret monastery to the remote Dek island and its ancient churches.',\n        content: `Lake Tana is Ethiopia's largest lake and one of Africa's most extraordinary bodies of water. Spanning 3,600 km² and dotted with 37 islands, it has been a cradle of Ethiopian Orthodox Christianity for nearly eight centuries.\n\n**Getting on the Water**\n\nThe most authentic way to experience Lake Tana is by boat. From Bahir Dar's lively lakefront, you can hire motorboats for full-day island-hopping tours or, for a more traditional experience, the papyrus tankwa — ancient reed boats still made and used by local fishermen using techniques unchanged for centuries.\n\n**Ura Kidane Mehret**\n\nThe most popular monastery is Ura Kidane Mehret on the Zege Peninsula, about 45 minutes by boat from Bahir Dar. Founded in the 14th century, the circular church is renowned for its extraordinary collection of painted murals covering every interior surface, depicting biblical scenes, Ethiopian saints, and historical events with vivid colour and remarkable detail. The monastery also houses a treasury of ancient crowns, crosses, and ceremonial items.\n\n**Kibran Gabriel**\n\nThis male-only island monastery, visible from Bahir Dar, is one of the lake's most important religious sites. The church contains the mummified remains of several Ethiopian emperors and is considered one of the holiest places in the country. The island's forest creates a mystical atmosphere that feels entirely removed from the modern world.\n\n**Narga Selassie**\n\nOn the far side of Dek Island, Narga Selassie was built in the 18th century by Empress Mentewab, one of Ethiopia's most powerful female rulers. The stone church, surrounded by ancient trees and enclosed within a circular wall of basalt, is considered one of the finest examples of Ethiopian ecclesiastical architecture.\n\n**Practical Tips**\n\n- Hire boats from Bahir Dar's official boat station near the main pier\n- Full-day tours typically visit 3–4 monasteries and cost around USD 50–80 per boat\n- Bring modest clothing (shoulders and knees covered) for monastery visits\n- Some monasteries do not permit women inside — ask your guide before entering\n- The best light for photography is early morning or late afternoon`,\n        category: 'Travel Guide',\n        author: 'Yohannes Tadesse',\n        authorAvatar: '/images/gal-08.jpg',\n        date: '2024-03-08',\n        readTime: '10 min read',\n        image: '/images/blog-lake-tana.jpg',\n        tags: [\n            'Lake Tana',\n            'Monasteries',\n            'Travel',\n            'Boat Tour'\n        ],\n        likes: 389\n    },\n    {\n        id: 3,\n        slug: 'blue-nile-falls-guide',\n        title: 'Blue Nile Falls Travel Guide: Everything You Need to Know',\n        excerpt: 'The ultimate guide to visiting Tis Abay — the Blue Nile Falls. When to go, how to get there, what to expect, and how to make the most of your visit.',\n        content: `The Blue Nile Falls, known locally as Tis Abay (Smoke of Fire), is one of Africa's most impressive waterfalls and arguably Ethiopia's most dramatic natural spectacle. Located 30 km south of Bahir Dar, the falls mark the point where the Blue Nile begins its long journey northward through Ethiopia and Sudan before joining the White Nile at Khartoum.\n\n**The Falls in Context**\n\nThe Blue Nile descends approximately 45 metres over a wide basalt ledge into a deep gorge, creating a thunderous roar and perpetual spray that can be seen from kilometres away. At peak flow (August–September), the falls stretch nearly 400 metres wide. During dry season, water flow decreases, but the reduced volume reveals beautiful rock formations and allows access to areas underwater during rains.\n\n**When to Visit**\n\nThe ideal time is October through December — shortly after the rainy season ends. The falls are still at impressive volume from the preceding rains, but the surrounding landscape is lush green, visibility is excellent, and the weather is pleasant. If maximum drama is your goal, visit in August or September (peak rains), though the gorge path can be muddy.\n\n**Getting There**\n\nFrom Bahir Dar: \n- Minibus from the main bus station (ETB 30, ~45 minutes to Tis Abay village)\n- Bajaj (auto-rickshaw) taxi (ETB 200–300 round trip)\n- Hired 4WD for groups (ETB 500–700)\n\nAt Tis Abay village, a 40-minute walk through farmland and along the Nile gorge leads to the viewpoints. Local guides (highly recommended) can be hired at the trailhead.\n\n**At the Falls**\n\nTwo main viewpoints offer different perspectives. The first gives a frontal view of the entire curtain of water. A suspension bridge leads to a second viewpoint with a closer, more dramatic angle. On sunny days, a permanent rainbow hovers in the spray — a photographer's dream.\n\n**Historical Note**\n\nA 17th-century stone bridge near the falls, built by the Portuguese explorer Pedro Páez, is one of the oldest in sub-Saharan Africa and makes for an interesting additional stop on your walk.`,\n        category: 'Travel Guide',\n        author: 'Selamawit Girma',\n        authorAvatar: '/images/gal-12.jpg',\n        date: '2024-04-20',\n        readTime: '9 min read',\n        image: '/images/blog-falls.jpg',\n        tags: [\n            'Blue Nile Falls',\n            'Waterfalls',\n            'Travel Guide',\n            'Nature'\n        ],\n        likes: 512\n    },\n    {\n        id: 4,\n        slug: 'cultural-experiences-bahir-dar',\n        title: 'Cultural Experiences You Can\\'t Miss in Bahir Dar',\n        excerpt: 'From the hypnotic shoulder movements of eskista dance to the rich flavours of doro wot, Bahir Dar offers some of Ethiopia\\'s most immersive cultural experiences.',\n        content: `Bahir Dar is not just a gateway to natural wonders — it is a living cultural landscape where ancient traditions coexist with modern Ethiopian life. Visitors who engage with local culture return home with memories far richer than any photograph.\n\n**Timkat: The Festival of Epiphany**\n\nIf your visit coincides with late January, you may be fortunate enough to witness Timkat, Ethiopia's most spectacular religious festival. Celebrating Christ's baptism, the festival involves processions of colourfully robed priests carrying the tabot (replica of the Ark of the Covenant) to Lake Tana, where worshippers bless themselves with the holy water. The atmosphere is electric with singing, drumming, and ululating crowds.\n\n**Coffee Ceremony**\n\nEthiopia is the birthplace of coffee, and the traditional coffee ceremony (jebena buna) is a cornerstone of social life. You will be invited to sit as your host roasts green coffee beans over charcoal, grinds them by hand, and brews three successive rounds in a clay jebena pot. It is a ritual of hospitality, community, and sensory pleasure that should not be rushed.\n\n**Eskista Dance**\n\nThe eskista is Ethiopia's traditional dance form, defined by complex shoulder and chest movements, curved postures, and a rhythmic, almost trancelike energy. In Bahir Dar, cultural restaurants often offer evening performances accompanied by traditional music from the krar and masenqo instruments. Attempting to join in is warmly encouraged by local performers.\n\n**Weaving Workshops**\n\nThe Amhara region is famous for its handwoven white cotton garments with decorative coloured borders. Visit one of Bahir Dar's weaving cooperatives to watch skilled artisans at traditional wooden looms produce the beautiful habesha kemis dresses and netela shawls. Many workshops welcome visitors and allow purchases of authentic handmade textiles directly from the weavers.`,\n        category: 'Culture',\n        author: 'Almaz Bekele',\n        authorAvatar: '/images/gal-12.jpg',\n        date: '2024-05-12',\n        readTime: '7 min read',\n        image: '/images/blog-culture.jpg',\n        tags: [\n            'Culture',\n            'Traditions',\n            'Food',\n            'Dance',\n            'Festivals'\n        ],\n        likes: 298\n    },\n    {\n        id: 5,\n        slug: 'best-places-to-visit',\n        title: '10 Best Places to Visit Around Bahir Dar in 2024',\n        excerpt: 'Our curated list of the absolute must-see attractions around Bahir Dar, from world-famous landmarks to hidden local gems that most tourists never discover.',\n        content: `Bahir Dar and its surroundings pack an extraordinary density of remarkable places into a relatively small area. Whether you have two days or two weeks, here are the ten experiences that should top your itinerary.\n\n**1. Blue Nile Falls (Tis Abay)**\nNo trip to Bahir Dar is complete without seeing Ethiopia's most dramatic waterfall. The 45-metre cascade is awe-inspiring, particularly in the weeks after the rainy season.\n\n**2. Ura Kidane Mehret Monastery**\nThe finest painted monastery on Lake Tana, with floor-to-ceiling biblical murals that are simply breathtaking in their detail and colour.\n\n**3. Sunset Boat Cruise on Lake Tana**\nHire a small motorboat for a late afternoon cruise. As the sun descends, the lake turns gold and the distant mountains turn purple — absolute magic.\n\n**4. Bezawit Hill at Dawn**\nDrive or hike to the hilltop before sunrise. The city and lake gradually reveal themselves in the growing light — one of the great views in East Africa.\n\n**5. Kibran Gabriel Island**\nThe most atmospheric of the monastery islands, surrounded by dense forest and accessible only by boat. The sense of stepping back in time is profound.\n\n**6. Zege Peninsula Coffee Forest**\nWalk through one of Ethiopia's last remaining wild coffee forests on the Zege Peninsula. Coffee plants grow wild beneath the forest canopy — pick a ripe red cherry and taste where coffee began.\n\n**7. Bahir Dar Saturday Market**\nThe weekly market draws traders and farmers from surrounding villages. Spices, textiles, pottery, livestock, and fresh produce create a vibrant sensory experience.\n\n**8. Narga Selassie on Dek Island**\nA full-day adventure to the far side of the lake to visit this 18th-century masterpiece of Ethiopian architecture in its remote island setting.\n\n**9. Traditional Tej House**\nSample tej (honey wine) at a local tej bet. Served in flask-shaped berele glasses, this ancient drink has been brewed in the region for thousands of years.\n\n**10. Blue Nile Gorge Viewpoint**\nA short drive from Bahir Dar, the gorge viewpoint offers vertiginous views down into the spectacular Blue Nile canyon — one of Africa's great geological features.`,\n        category: 'Tips',\n        author: 'Yohannes Tadesse',\n        authorAvatar: '/images/gal-08.jpg',\n        date: '2024-06-01',\n        readTime: '11 min read',\n        image: '/images/blog-best-places.jpg',\n        tags: [\n            'Top 10',\n            'Travel Tips',\n            'Attractions',\n            'Bahir Dar'\n        ],\n        likes: 647\n    }\n];\n// ─── Gallery Images — all local real photos ───────────────────────────────────\nconst galleryImages = [\n    {\n        id: 1,\n        src: '/images/gal-01.jpg',\n        alt: 'Blue Nile Falls (Tis Abay) — powerful waterfall on the Blue Nile river, 30km from Bahir Dar',\n        category: 'Nature',\n        title: 'Blue Nile Falls'\n    },\n    {\n        id: 2,\n        src: '/images/gal-02.jpg',\n        alt: 'Lake Tana — Ethiopia\\'s largest lake and source of the Blue Nile, Bahir Dar shoreline',\n        category: 'Lake',\n        title: 'Lake Tana'\n    },\n    {\n        id: 3,\n        src: '/images/gal-03.jpg',\n        alt: 'Bahir Dar city — wide palm-lined boulevards of Ethiopia\\'s garden city',\n        category: 'City',\n        title: 'Bahir Dar City'\n    },\n    {\n        id: 4,\n        src: '/images/gal-04.jpg',\n        alt: 'Kibran Gabriel island monastery on Lake Tana, one of Ethiopia\\'s holiest sites',\n        category: 'Heritage',\n        title: 'Kibran Gabriel Monastery'\n    },\n    {\n        id: 5,\n        src: '/images/gal-05.jpg',\n        alt: 'Lake Tana scenic view — the vast inland sea of Ethiopia at dawn',\n        category: 'Lake',\n        title: 'Lake Tana at Dawn'\n    },\n    {\n        id: 6,\n        src: '/images/gal-06.jpg',\n        alt: 'Lake Tana and surrounding Ethiopian highland landscape',\n        category: 'Nature',\n        title: 'Ethiopian Highlands'\n    },\n    {\n        id: 7,\n        src: '/images/gal-07.jpg',\n        alt: 'Bahir Dar city aerial view — capital of Amhara Region, Ethiopia',\n        category: 'City',\n        title: 'Bahir Dar Aerial'\n    },\n    {\n        id: 8,\n        src: '/images/gal-08.jpg',\n        alt: 'Timkat festival — Ethiopian Epiphany celebration with colourful processions at Lake Tana',\n        category: 'Culture',\n        title: 'Timkat Festival'\n    },\n    {\n        id: 9,\n        src: '/images/gal-09.jpg',\n        alt: 'Traditional papyrus tankwa boats on Lake Tana — used by fishermen for centuries',\n        category: 'Lake',\n        title: 'Papyrus Tankwa Boats'\n    },\n    {\n        id: 10,\n        src: '/images/gal-10.jpg',\n        alt: 'Inside Ura Kidane Mehret monastery — ancient Ethiopian Orthodox murals on Zege Peninsula',\n        category: 'Heritage',\n        title: 'Ura Kidane Mehret Murals'\n    },\n    {\n        id: 11,\n        src: '/images/gal-11.jpg',\n        alt: 'Lake Tana golden sunset — tranquil waters reflecting the last light of day',\n        category: 'Lake',\n        title: 'Lake Tana Sunset'\n    },\n    {\n        id: 12,\n        src: '/images/gal-12.jpg',\n        alt: 'Timkat celebration — Ethiopian Orthodox worshippers in traditional white garments',\n        category: 'Culture',\n        title: 'Ethiopian Orthodox Culture'\n    },\n    {\n        id: 13,\n        src: '/images/gal-13.jpg',\n        alt: 'Ura Kidane Mehret — 14th-century monastery on Zege Peninsula, Lake Tana',\n        category: 'Heritage',\n        title: 'Ura Kidane Mehret'\n    },\n    {\n        id: 14,\n        src: '/images/gal-14.jpg',\n        alt: 'Bahir Dar local market — vibrant trading hub with traditional crafts and spices',\n        category: 'Culture',\n        title: 'Bahir Dar Market'\n    },\n    {\n        id: 15,\n        src: '/images/gal-15.jpg',\n        alt: 'Kibran Gabriel monastery island — male-only sanctuary housing royal mummies on Lake Tana',\n        category: 'Heritage',\n        title: 'Kibran Gabriel Island'\n    },\n    {\n        id: 16,\n        src: '/images/gal-16.jpg',\n        alt: 'Lake Tana at sunset — Zege Peninsula in the distance, papyrus reeds in the foreground',\n        category: 'Lake',\n        title: 'Lake Tana Evening'\n    }\n];\n// ─── Testimonials ────────────────────────────────────────────────────────────\nconst testimonials = [\n    {\n        id: 1,\n        name: 'Sarah Mitchell',\n        location: 'London, UK',\n        avatar: '/images/gal-08.jpg',\n        rating: 5,\n        text: 'Bahir Dar completely exceeded my expectations. The Blue Nile Falls at full flow left me speechless, and the boat trip to the island monasteries was the highlight of my entire Africa trip. The warmth of the local people made it truly unforgettable.',\n        destination: 'Blue Nile Falls & Lake Tana'\n    },\n    {\n        id: 2,\n        name: 'Marcus Weber',\n        location: 'Munich, Germany',\n        avatar: '/images/gal-12.jpg',\n        rating: 5,\n        text: 'As a history enthusiast, the ancient monasteries of Lake Tana were beyond anything I could have imagined. Stepping inside Ura Kidane Mehret and seeing those 17th-century murals was like entering a living museum. A truly profound experience.',\n        destination: 'Ura Kidane Mehret Monastery'\n    },\n    {\n        id: 3,\n        name: 'Amina Hassan',\n        location: 'Dubai, UAE',\n        avatar: '/images/gal-08.jpg',\n        rating: 5,\n        text: 'Watching the sunrise from Bezawit Hill with Lake Tana shimmering below was one of the most beautiful moments of my life. Bahir Dar is the perfect blend of natural beauty, ancient culture, and genuine Ethiopian hospitality.',\n        destination: 'Bezawit Hill & Bahir Dar City'\n    },\n    {\n        id: 4,\n        name: 'James Okoye',\n        location: 'Lagos, Nigeria',\n        avatar: '/images/gal-12.jpg',\n        rating: 5,\n        text: 'The food alone is worth the trip! Doro wot on injera by the lake, fresh tilapia from Tana, tej honey wine in a local tej house — Bahir Dar has one of the most exciting culinary scenes in Africa. I\\'ll definitely return.',\n        destination: 'Bahir Dar City'\n    }\n];\n// ─── Stats ────────────────────────────────────────────────────────────────────\nconst stats = [\n    {\n        label: 'Annual Visitors',\n        value: '500K+',\n        icon: 'users'\n    },\n    {\n        label: 'Island Monasteries',\n        value: '20+',\n        icon: 'landmark'\n    },\n    {\n        label: 'Bird Species',\n        value: '200+',\n        icon: 'bird'\n    },\n    {\n        label: 'Sq km of Lake',\n        value: '3,600',\n        icon: 'waves'\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/data.js\n");

